#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long R; scanf("%d %lld", &N, &R);
        long long *A = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &A[i]);
        long long d = LLONG_MAX;
        long long *B = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++){
            scanf("%lld", &B[i]);
            long long net = A[i] - B[i];
            if(net < d) d = net;
        }
        long long ans = 0;
        for(int i=0;i<N;i++) if(A[i] <= R){
            long long cnt = 1 + (R - A[i]) / d;
            if(cnt > ans) ans = cnt;
        }
        printf("%lld\n", ans);
        free(A); free(B);
    }
    return 0;
}

