const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const R = input[idx++];
  const A = new Array(N);
  for (let i = 0; i < N; i++) A[i] = input[idx++];
  let d = Number.MAX_SAFE_INTEGER;
  const B = new Array(N);
  for (let i = 0; i < N; i++) {
    B[i] = input[idx++];
    const net = A[i] - B[i];
    if (net < d) d = net;
  }
  let ans = 0;
  for (let i = 0; i < N; i++) {
    if (A[i] <= R) {
      const cnt = 1 + Math.floor((R - A[i]) / d);
      if (cnt > ans) ans = cnt;
    }
  }
  outputs.push(String(ans));
}
